"use client";

import { motion, useScroll, useTransform, useSpring } from "framer-motion";
import Image from "next/image";
import { useEffect, useState, RefObject } from "react";

export default function TravelingProduct({ triggerRef }: { triggerRef: RefObject<HTMLElement | null> }) {
  const { scrollYProgress } = useScroll();
  const { scrollYProgress: fadeProgress } = useScroll({
    target: triggerRef,
    offset: ["start bottom", "end center"] 
  });

  const [isClient, setIsClient] = useState(false);

  useEffect(() => {
    setIsClient(true);
  }, []);

  // Let the image scale in from 0.2, 0% opacity to original scale and 100% opacity 
  // starting exactly from the text based on `fadeProgress`
  const opacity = useTransform(fadeProgress, [0, 1], [0, 1]);
  const scale = useTransform(fadeProgress, [0, 1], [0.2, 1]);
  
  // Heavy, premium, dampened spring for the rest of the journey
  const springProgress = useSpring(scrollYProgress, {
    stiffness: 100,
    damping: 30,
    restDelta: 0.001
  });

  const rotate = useTransform(springProgress, [0.65, 0.9], [0, 15]);
  const y = useTransform(springProgress, [0.65, 0.9, 1], ["0%", "30%", "60%"]);
  
  // When hitting footer (progress 1.0), it settles in center
  const x = useTransform(springProgress, [0.9, 1], ["0%", "0%"]);

  if (!isClient) return null;

  return (
    <motion.div 
      style={{ opacity, rotate, scale, y, x }}
      className="fixed inset-0 z-40 flex items-center justify-center pointer-events-none"
    >
      <div className="relative w-screen h-screen flex items-center justify-center">
        <Image
          src="/images/clean-bottle-hero.png"
          alt="Clean All-In-One Bottle"
          width={800}
          height={800}
          className="w-auto h-[60vh] object-contain drop-shadow-2xl"
          priority
        />
      </div>
    </motion.div>
  );
}

